import json
import urllib.request as request
from urllib.parse import urlparse

def readJSON(url):
    '''
    Read a json file from a url
    and return the parsed json object
    '''
    # Define an allowlist of safe domains to prevent SSRF
    # This should be updated based on your specific requirements
    ALLOWED_DOMAINS = {'example.com', 'api.trusted.org'}
    ALLOWED_SCHEMES = {'http', 'https'}

    try:
        parsed_url = urlparse(url)

        # Validate scheme and hostname
        if parsed_url.scheme not in ALLOWED_SCHEMES:
            raise ValueError("Invalid URL scheme")

        if parsed_url.hostname not in ALLOWED_DOMAINS:
            raise ValueError("Access to the provided domain is not allowed")

        # Use a User-Agent header to prevent some basic bot filters
        headers = {'User-Agent': 'Python-Request-Agent/1.0'}
        req = request.Request(url, headers=headers)

        with request.urlopen(req, timeout=10) as response:
            # Check if the response is successful
            if response.status != 200:
                raise Exception(f"Failed to fetch JSON. Status code: {response.status}")

            data = response.read().decode('utf-8')
            return json.loads(data)

    except Exception as e:
        # In a production environment, log the error properly
        return {"error": str(e)}
