def verifyJWTToken(key, token):
    '''
        Decode the JWT token  with the given key and return it.
    '''
    try:
        # Using jwt.decode with the key ensures both signature verification 
        # and expiration (exp) checks are performed.
        # By default, verify=True is enforced in modern versions.
        decoded_payload = jwt.decode(token, key, algorithms=["HS256"])
        return decoded_payload
    except jwt.ExpiredSignatureError:
        # Handle expired tokens
        return {"error": "Token has expired"}
    except jwt.InvalidTokenError:
        # Handle invalid tokens (wrong signature, malformed, etc.)
        return {"error": "Invalid token"}
    except Exception as e:
