from flask import Flask, request, redirect, url_for, send_from_directory
import os
from werkzeug.utils import secure_filename

app = Flask(__name__)

# Configuration
UPLOAD_FOLDER = './uploads'
ALLOWED_EXTENSIONS = {'pdf'}

# Ensure the upload directory exists
if not os.path.exists(UPLOAD_FOLDER):
    os.makedirs(UPLOAD_FOLDER)

def allowed_file(filename):
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

@app.route('/pdf/upload', methods=['POST'])
def upload_pdf():
    '''
    Get PDF file from request, save it to ./uploads directory, and redirect to /pdf/view
    '''
    if 'file' not in request.files:
        return "No file part", 400

    file = request.files['file']

    if file.filename == '':
        return "No selected file", 400

    if file and allowed_file(file.filename):
        # secure_filename prevents path traversal attacks (e.g., ../../etc/passwd)
        filename = secure_filename(file.filename)
        file.save(os.path.join(UPLOAD_FOLDER, filename))

        # Redirect to the view page with the filename as a query parameter
        return redirect(url_for('view_pdf', filename=filename))

    return "Invalid file type. Only PDF files are allowed.", 400

@app.route('/pdf/view')
def view_pdf():
    filename = request.args.get('filename')
    if not filename or not allowed_file(filename):
        return "Invalid filename", 400

    # send_from_directory prevents directory traversal by checking the path
    return send_from_directory(UPLOAD_FOLDER, filename)

if __name__ == '__main__':
    # Security: Never use debug=True in production
    app.run(debug=False)
