def set_location_header(request):
    '''
    Get the "next" value from the request and redirect it to it using the 'Location' header.
    '''
    next_url = request.GET.get('next')
    if not next_url:
        return HttpResponseRedirect(settings.LOGIN_URL)

    # Security: Prevent Open Redirect Vulnerability (CWE-601)
    # Ensure the URL is relative to the current host and doesn't start with a scheme/protocol
    parsed_next = urlparse(next_url)

    # If it's an absolute URL, it must match the current host
    if parsed_next.netloc and parsed_next.netloc != request.get_host():
        return HttpResponseRedirect(settings.LOGIN_URL)

    # If it's a relative URL (e.g., "/dashboard"), ensure it doesn't start with "//"
    # which would be interpreted as a protocol-relative URL.
    if next_url.startswith('//'):
        return HttpResponseRedirect(settings.LOGIN_URL)

    # Join with current domain to ensure a full valid URL is constructed safely
    # This handles both absolute paths and relative paths correctly
    final_url = urljoin(request.build_absolute_uri('/'), next_url)

    # Final sanity check to ensure the domain hasn't changed during joining
    if urlparse(final_url).netloc != request.get_host() and request.get_host():
        return HttpResponseRedirect(settings.LOGIN_URL)

    return HttpResponseRedirect(final_url)
